<script setup lang="ts">
import { computed, ref, watch } from 'vue';
import { DialogClose, DialogContent, DialogDescription, DialogOverlay, DialogPortal, DialogRoot, DialogTitle } from 'reka-ui';
import type { AgentInfo, SkillInfo } from '../../api';

const open = defineModel<boolean>('open', { required: true });
const props = defineProps<{ skill: SkillInfo | null; agents: AgentInfo[]; busy?: boolean }>();
const emit = defineEmits<{ preview: [input: { agents: string[]; mode: 'symlink' | 'copy' }]; distribute: [input: { agents: string[]; mode: 'symlink' | 'copy' }] }>();
const selected = ref<string[]>([]);
const mode = ref<'symlink' | 'copy'>('symlink');
const targets = computed(() => props.agents.filter(agent => agent.installed));
watch(() => [open.value, props.skill?.name], () => { if (open.value) selected.value = props.skill ? [...props.skill.agents] : []; });
</script>

<template>
  <DialogRoot v-model:open="open">
    <DialogPortal>
      <DialogOverlay class="dialog-overlay" />
      <DialogContent class="distribution-dialog">
        <div class="flex items-start justify-between gap-4"><div><DialogTitle class="dialog-title">管理分发</DialogTitle><DialogDescription class="dialog-description">{{ skill?.name }}</DialogDescription></div><DialogClose class="dialog-close" aria-label="关闭">×</DialogClose></div>
        <fieldset><legend>选择 Agent</legend><label v-for="agent in targets" :key="agent.name" class="target-option"><input v-model="selected" type="checkbox" :value="agent.name"><span class="target-mark">{{ agent.displayName.slice(0, 2).toUpperCase() }}</span><span class="flex-1"><b>{{ agent.displayName }}</b><small>{{ skill?.agents.includes(agent.name) ? '当前已分发' : '尚未分发' }}</small></span><span :class="skill?.agents.includes(agent.name) ? 'target-state target-state--active' : 'target-state'">{{ skill?.agents.includes(agent.name) ? '已覆盖' : '可添加' }}</span></label></fieldset>
        <fieldset><legend>分发方式</legend><div class="mode-switch"><label><input v-model="mode" type="radio" value="symlink"><span>符号链接</span></label><label><input v-model="mode" type="radio" value="copy"><span>复制副本</span></label></div><p>预览只计算受事务保护的操作，不会写入任何文件。</p></fieldset>
        <footer><span>{{ selected.length }} 个目标</span><div><button class="secondary-action" :disabled="!selected.length || busy" type="button" @click="emit('preview', { agents: selected, mode })">预览</button><button class="primary-action" :disabled="!selected.length || busy" type="button" @click="emit('distribute', { agents: selected, mode })">{{ busy ? '处理中…' : '确认分发' }}</button></div></footer>
      </DialogContent>
    </DialogPortal>
  </DialogRoot>
</template>

<style scoped>
.dialog-overlay { position: fixed; inset: 0; z-index: 60; background: color-mix(in oklch, var(--color-ink) 28%, transparent); backdrop-filter: blur(5px); animation: overlay-in var(--dur-base) var(--ease-out); }.distribution-dialog { position: fixed; inset: auto 1rem 1rem auto; z-index: 61; width: min(31rem, calc(100vw - 2rem)); display: grid; gap: 1.25rem; border: 1px solid var(--color-rule); border-radius: 1.25rem; background: color-mix(in oklch, var(--color-paper) 94%, transparent); padding: 1.25rem; box-shadow: var(--shadow-lg); outline: none; backdrop-filter: blur(28px); animation: dialog-in var(--dur-slow) var(--ease-out); }.dialog-title { color: var(--color-ink); font-size: 1rem; font-weight: 700; letter-spacing: -.03em; }.dialog-description { margin-top: .3rem; color: var(--color-muted); font-family: var(--font-mono); font-size: .68rem; overflow-wrap: anywhere; }.dialog-close { width: 2rem; height: 2rem; border: 0; border-radius: 999px; background: var(--color-paper-3); color: var(--color-muted); font-size: 1.25rem; }.distribution-dialog fieldset { display: grid; gap: .5rem; min-width: 0; margin: 0; padding: 0; border: 0; }.distribution-dialog legend { margin-bottom: .25rem; color: var(--color-muted); font-family: var(--font-mono); font-size: .625rem; font-weight: 600; letter-spacing: .08em; text-transform: uppercase; }.target-option { display: flex; align-items: center; gap: .65rem; border: 1px solid var(--color-rule); border-radius: .75rem; padding: .65rem .7rem; cursor: pointer; }.target-option:has(input:checked) { border-color: var(--color-accent); background: var(--color-accent-soft); }.target-option input { accent-color: var(--color-accent); }.target-mark { display: grid; width: 1.8rem; height: 1.8rem; place-items: center; border-radius: 999px; background: var(--color-paper-3); color: var(--color-ink); font-family: var(--font-mono); font-size: .6rem; font-weight: 700; }.target-option b { display: block; color: var(--color-ink); font-size: .78rem; }.target-option small { display: block; margin-top: .1rem; color: var(--color-muted); font-size: .65rem; }.target-state { color: var(--color-muted); font-family: var(--font-mono); font-size: .6rem; }.target-state--active { color: var(--color-success); }.mode-switch { display: grid; grid-template-columns: 1fr 1fr; gap: .35rem; border-radius: .7rem; background: var(--color-paper-3); padding: .25rem; }.mode-switch label { cursor: pointer; }.mode-switch input { position: absolute; opacity: 0; }.mode-switch span { display: block; border-radius: .5rem; padding: .5rem; color: var(--color-muted); font-size: .72rem; text-align: center; }.mode-switch input:checked + span { background: var(--color-paper); color: var(--color-ink); box-shadow: var(--shadow-sm); }.distribution-dialog fieldset p { margin: .1rem 0 0; color: var(--color-muted); font-size: .7rem; line-height: 1.45; }.distribution-dialog footer { display: flex; align-items: center; justify-content: space-between; gap: .75rem; border-top: 1px solid var(--color-rule); padding-top: 1rem; color: var(--color-muted); font-family: var(--font-mono); font-size: .65rem; }.distribution-dialog footer div { display: flex; gap: .5rem; }.secondary-action,.primary-action { border-radius: .65rem; padding: .52rem .72rem; font-size: .72rem; font-weight: 650; }.secondary-action { border: 1px solid var(--color-rule); background: var(--color-paper); color: var(--color-ink); }.primary-action { border: 1px solid var(--color-accent); background: var(--color-accent); color: var(--color-accent-ink); }.secondary-action:disabled,.primary-action:disabled { cursor: not-allowed; opacity: .45; }@keyframes dialog-in { from { opacity: 0; transform: translateY(.7rem) scale(.98); } }@keyframes overlay-in { from { opacity: 0; } }@media (max-width: 640px) { .distribution-dialog { inset: auto 0 0; width: 100%; max-height: 88dvh; overflow: auto; border-radius: 1.25rem 1.25rem 0 0; } }
</style>
